#include <vector>
#include <sstream>
#include <cmath> // For std::abs

// This function defines the correct behavior for reversing an integer.
// It is used by the test harness to determine the 'expected' output for a given input.
std::string get_expected_reverse(int n_val) {
    if (n_val == 0) {
        return "0";
    }

    bool is_negative = false;
    if (n_val < 0) {
        is_negative = true;
        n_val = -n_val;
    }

    long long reversed_num = 0; // Use long long to prevent overflow during reversal for larger inputs.
                               // Assumes reversed number fits within long long.
    while (n_val > 0) {
        int digit = n_val % 10;
        reversed_num = reversed_num * 10 + digit;
        n_val /= 10;
    }

    std::stringstream ss;
    if (is_negative) {
        ss << "-";
    }
    ss << reversed_num;
    return ss.str();
}

